import{_ as e,o as t,c as o,ae as l}from"./chunks/framework.Co1PSFSm.js";const r="/assets/image-4.tuZMB1lK.png",i="/assets/image-2.Eut_7md6.png",p="/assets/image.Dr14laL6.png",h="/assets/image-3.B4eMvKcO.png",n="/assets/image-1.BxPCAnK_.png",_=JSON.parse('{"title":"我的游戏清单","description":"","frontmatter":{},"headers":[],"relativePath":"blog/我的游戏清单.md","filePath":"blog/我的游戏清单.md","lastUpdated":1779870671000}'),c={name:"blog/我的游戏清单.md"};function s(d,a,u,b,q,k){return t(),o("div",null,[...a[0]||(a[0]=[l('<h1 id="我的游戏清单" tabindex="-1">我的游戏清单 <a class="header-anchor" href="#我的游戏清单" aria-label="Permalink to &quot;我的游戏清单&quot;">​</a></h1><p>整理一下我喜欢的游戏，标注是否已玩过。</p><h2 id="主要游玩设备" tabindex="-1">主要游玩设备 <a class="header-anchor" href="#主要游玩设备" aria-label="Permalink to &quot;主要游玩设备&quot;">​</a></h2><ul><li>联想平板 Y700</li><li>苹果手机 14 Plus</li><li>MacBook Air M5</li><li>Win笔记本 小米14</li></ul><h2 id="游戏列表" tabindex="-1">游戏列表 <a class="header-anchor" href="#游戏列表" aria-label="Permalink to &quot;游戏列表&quot;">​</a></h2><h3 id="《dnf》-已玩" tabindex="-1">《DNF》[已玩] <a class="header-anchor" href="#《dnf》-已玩" aria-label="Permalink to &quot;《DNF》[已玩]&quot;">​</a></h3><blockquote><p>提示：此处需要添加游戏截图</p></blockquote><p>玩了很多年，每次登录都有熟悉的感觉，刷图的时候很放松。</p><p>但太费钱了，没好武器图都过不了，后弃坑。</p><h3 id="《王者荣耀》-已玩" tabindex="-1">《王者荣耀》[已玩] <a class="header-anchor" href="#《王者荣耀》-已玩" aria-label="Permalink to &quot;《王者荣耀》[已玩]&quot;">​</a></h3><blockquote><p>提示：此处需要添加游戏截图</p></blockquote><p>和朋友开黑必备，有时候一局能玩很久，挺上头的。</p><p>一分不氪玩了很多年了。</p><h3 id="《阴阳师》-已玩" tabindex="-1">《阴阳师》[已玩] <a class="header-anchor" href="#《阴阳师》-已玩" aria-label="Permalink to &quot;《阴阳师》[已玩]&quot;">​</a></h3><blockquote><p>提示：此处需要添加游戏截图</p></blockquote><p>画面确实好看，抽卡有点费钱，不过剧情还挺有意思的。</p><p>后续版本出得太快，英雄/式神出得太快，就不玩了。</p><h3 id="《微信小游戏-别踩白块》-已玩-我自己做的微信小游戏" tabindex="-1">《微信小游戏：别踩白块》[已玩]（我自己做的微信小游戏） <a class="header-anchor" href="#《微信小游戏-别踩白块》-已玩-我自己做的微信小游戏" aria-label="Permalink to &quot;《微信小游戏：别踩白块》[已玩]（我自己做的微信小游戏）&quot;">​</a></h3><blockquote><p>提示：此处需要添加游戏截图</p></blockquote><p>自己动手做的小游戏，虽然简单，但看着自己作品上线还是挺有成就感的。</p><h3 id="《塞尔达传说-旷野之息》-已玩" tabindex="-1">《塞尔达传说：旷野之息》 [已玩] <a class="header-anchor" href="#《塞尔达传说-旷野之息》-已玩" aria-label="Permalink to &quot;《塞尔达传说：旷野之息》 [已玩]&quot;">​</a></h3><blockquote><p>提示：此处需要添加游戏截图</p></blockquote><p>这个游戏让我愿意慢慢玩，到处探索，没有任务压力，很享受。</p><p>还有很多花活操作：风弹、飞雷神、盾反炸弹、盾反炸弹二段跳、破冰起飞 ...</p><p>学会一个风弹，就是另一种游戏体验了。</p><h3 id="《塞尔达传说-王国之泪》-已玩" tabindex="-1">《塞尔达传说：王国之泪》 [已玩] <a class="header-anchor" href="#《塞尔达传说-王国之泪》-已玩" aria-label="Permalink to &quot;《塞尔达传说：王国之泪》 [已玩]&quot;">​</a></h3><blockquote><p>提示：此处需要添加游戏截图</p></blockquote><p>个人感觉没旷野之息好玩，画风暗黑、潮湿、破败，某些怪物恶心，没有旷野之息生机勃勃的感觉。</p><p>但王国之泪可以玩建造diy，综合来看，也算好玩。</p><h3 id="《动物森友会》-已玩" tabindex="-1">《动物森友会》 [已玩] <a class="header-anchor" href="#《动物森友会》-已玩" aria-label="Permalink to &quot;《动物森友会》 [已玩]&quot;">​</a></h3><blockquote><p>提示：此处需要添加游戏截图</p></blockquote><p>个人感觉很轻松，主要是画风可爱，不需要复杂操作。</p><p>计划给小孩子玩玩。</p><h3 id="《马里奥赛车8》-已玩" tabindex="-1">《马里奥赛车8》 [已玩] <a class="header-anchor" href="#《马里奥赛车8》-已玩" aria-label="Permalink to &quot;《马里奥赛车8》 [已玩]&quot;">​</a></h3><blockquote><p>提示：此处需要添加游戏截图</p></blockquote><p>陪家里孩子玩的，卡通画风，赛道新奇，非常推荐给孩子玩。</p><h2 id="想玩的游戏" tabindex="-1">想玩的游戏 <a class="header-anchor" href="#想玩的游戏" aria-label="Permalink to &quot;想玩的游戏&quot;">​</a></h2><h3 id="《燕云十六京》" tabindex="-1">《燕云十六京》 <a class="header-anchor" href="#《燕云十六京》" aria-label="Permalink to &quot;《燕云十六京》&quot;">​</a></h3><p><img src="'+r+'" alt="alt text"></p><p>据说是古风类的开放世界，抽空体验一下</p><h3 id="《pico-park2》" tabindex="-1">《pico park2》 <a class="header-anchor" href="#《pico-park2》" aria-label="Permalink to &quot;《pico park2》&quot;">​</a></h3><p><img src="'+i+'" alt="alt text"></p><h3 id="《空之轨迹》" tabindex="-1">《空之轨迹》 <a class="header-anchor" href="#《空之轨迹》" aria-label="Permalink to &quot;《空之轨迹》&quot;">​</a></h3><p>画风挺喜欢的，还没空玩</p><p><img src="'+p+'" alt="alt text"></p><h3 id="《迷雾北境》" tabindex="-1">《迷雾北境》 <a class="header-anchor" href="#《迷雾北境》" aria-label="Permalink to &quot;《迷雾北境》&quot;">​</a></h3><p>依然是画风挺喜欢</p><p><img src="'+h+'" alt="alt text"></p><h2 id="不适合我的游戏" tabindex="-1">不适合我的游戏 <a class="header-anchor" href="#不适合我的游戏" aria-label="Permalink to &quot;不适合我的游戏&quot;">​</a></h2><h3 id="《刺客信条》" tabindex="-1">《刺客信条》 <a class="header-anchor" href="#《刺客信条》" aria-label="Permalink to &quot;《刺客信条》&quot;">​</a></h3><blockquote><p>提示：此处需要添加游戏截图</p></blockquote><p>太写实了，但又没完全真实，自由度也没那么高。</p><p>默认设置的视角转动太快，容易晕，不想花时间设置。</p><h3 id="《马里奥奥德赛》" tabindex="-1">《马里奥奥德赛》 <a class="header-anchor" href="#《马里奥奥德赛》" aria-label="Permalink to &quot;《马里奥奥德赛》&quot;">​</a></h3><blockquote><p>提示：此处需要添加游戏截图</p></blockquote><p>可能是手柄的原因，不适合我的手柄。</p><p>只能一个人玩，另一个人只能当帽子。</p><p>对于小孩子来说操作比较复杂，对于我来说，画风又过于低龄。</p><h3 id="《怪物猎人-崛起》" tabindex="-1">《怪物猎人 崛起》 <a class="header-anchor" href="#《怪物猎人-崛起》" aria-label="Permalink to &quot;《怪物猎人 崛起》&quot;">​</a></h3><p><img src="'+n+'" alt="alt text"></p><p>不喜欢这种页游风。</p><hr><p>这份清单会持续更新，记录那些给我带来快乐的游戏时光。</p>',63)])])}const f=e(c,[["render",s]]);export{_ as __pageData,f as default};
